transform_js:
const datesObj = {}; const nameObj = {};
rawData.rows.forEach(r => {
  datesObj[r.date] = true;
  nameObj[r.name] = true;
});
const dates = Object.keys(datesObj);
const names = Object.keys(nameObj);
const seriesData = names.map(n => {
    return {
       name: n,
       type: 'line',
       smooth: true,
       symbolSize: 15,
       lineStyle: { width: 4 },
       data: dates.map(d => {
          const found = rawData.rows.find(r => r.date === d && r.name === n);
          return found ? found.rank : null;
       })
    };
});
transformedData = { dates, seriesData };

echarts_js:
option = {
  title: {
    text: 'Ranking History (Bump Chart)',
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: '{a} <br/>{b} : Rank {c}'
  },
  legend: {
    bottom: '5%'
  },
  grid: { top: '15%', left: '10%', right: '10%', bottom: '15%' },
  xAxis: {
    type: 'category',
    data: transformedData.dates,
    splitLine: { show: true },
    boundaryGap: false
  },
  yAxis: {
    type: 'value',
    inverse: true,
    min: 1,
    max: 4,
    interval: 1,
    axisLabel: {
       formatter: '#{value}'
    }
  },
  series: transformedData.seriesData
};
